/* SDK da GameDistribution Neutralizado para Jogo Offline (Sem CORS) */
(function() {
    "use strict";
    
    // Cria o objeto global que o jogo procura
    window.gamedistribution = window.gamedistribution || {};
    window.GD_OPTIONS = window.GD_OPTIONS || {};
    
    // Cria uma instância falsa com as funções que o jogo tenta chamar
    var GDStub = function() {
        this.showAd = function() {
            console.log("GD Ad solicitado e pulado automaticamente.");
            if (typeof window.GD_OPTIONS.onEvent === 'function') {
                window.GD_OPTIONS.onEvent({ name: "SDK_GAME_START" });
            }
            return Promise.resolve();
        };
        this.init = function() {
            console.log("GD SDK Inicializado localmente.");
            if (typeof window.GD_OPTIONS.onEvent === 'function') {
                window.GD_OPTIONS.onEvent({ name: "SDK_READY" });
            }
        };
        this.resumeGame = function() {};
        this.pauseGame = function() {};
        this.openConsole = function() {};
    };

    var instance = new GDStub();

    // Injeta as funções falsas no escopo global
    Object.keys(instance).forEach(function(key) {
        window.gamedistribution[key] = instance[key];
    });

    // Executa a inicialização fake para o jogo achar que o SDK carregou
    setTimeout(function() {
        if (typeof window.GD_OPTIONS.onEvent === 'function') {
            window.GD_OPTIONS.onEvent({ name: "SDK_READY" });
        }
    }, 100);

    console.log("GameDistribution CORS Bypass aplicado! Pronto para jogar 100% offline.");
})();
